document.addEventListener("DOMContentLoaded",function(){const e=new URLSearchParams(window.location.search).get("token");if(e)window.location.replace("/supplier-dashboard.html?token="+encodeURIComponent(e));else{var t=document.getElementById("loading-state"),n=document.getElementById("error-state"),o=document.getElementById("error-message");t&&(t.style.display="none"),o&&(o.textContent="No access token provided. Please use the link from your email."),n&&(n.style.display="block")}});
